async function ensureRlsHardening() {
  let client = null;
  try {
    const dbUrl = process.env.SUPABASE_DATABASE_URL;
    if (!dbUrl) return;
    client = new pg3.Client({ connectionString: dbUrl, connectionTimeoutMillis: 1e4 });
    await client.connect();
    const { rows } = await client.query(
      `SELECT relname FROM pg_class cl JOIN pg_namespace n ON n.oid = cl.relnamespace
       WHERE n.nspname = 'public' AND cl.relkind = 'r' AND NOT cl.relrowsecurity`
    );
    if (rows.length > 0) {
      await client.query(`DO $$
        DECLARE r record;
        BEGIN
          FOR r IN SELECT relname FROM pg_class cl JOIN pg_namespace n ON n.oid = cl.relnamespace
                   WHERE n.nspname = 'public' AND cl.relkind = 'r' AND NOT cl.relrowsecurity
          LOOP
            EXECUTE format('ALTER TABLE public.%I ENABLE ROW LEVEL SECURITY', r.relname);
          END LOOP;
        END $$`);
      console.log(`[db-init] RLS habilitado em ${rows.length} tabela(s): ${rows.map((r) => r.relname).join(", ")}`);
    }
    for (const t of RLS_FRONTEND_POLICY_TABLES) {
      await client.query(`DO $$ BEGIN
        IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE schemaname='public' AND tablename='${t}' AND policyname='${t}_all') THEN
          CREATE POLICY ${t}_all ON public.${t} FOR ALL TO authenticated
            USING (is_app_user((SELECT auth.uid())))
            WITH CHECK (is_app_user((SELECT auth.uid())));
        END IF;
      END $$`).catch((e) => console.warn(`[db-init] policy ${t}:`, e?.message));
    }
    if (rows.length > 0) {
      await client.query(`NOTIFY pgrst, 'reload schema'`).catch(() => {
      });
    }
  } catch (e) {
    console.error("[db-init] \u26A0\uFE0F ensureRlsHardening FALHOU \u2014 tabelas novas podem estar sem RLS:", e?.message);
  } finally {
    if (client) await client.end().catch(() => {
    });
  }
}
async function ensureRealtimePublication() {
  try {
    const { data: existing } = await supabaseAdmin.rpc("exec_sql", {
      query: `SELECT tablename FROM pg_publication_tables WHERE pubname = 'supabase_realtime'`
    });
    const existingTables = /* @__PURE__ */ new Set();
    if (Array.isArray(existing)) {
      existing.forEach((r) => existingTables.add(r.tablename));
    }
    const missing = REALTIME_TABLES.filter((t) => !existingTables.has(t));
    for (const table of missing) {
      try {
        await execSql(`ALTER PUBLICATION supabase_realtime ADD TABLE ${table}`);
      } catch {
      }
    }
    const toDrop = REALTIME_TABLES_TO_DROP.filter((t) => existingTables.has(t));
    for (const table of toDrop) {
      try {
        await execSql(`ALTER PUBLICATION supabase_realtime DROP TABLE ${table}`);
      } catch {
      }
    }
    if (missing.length === 0 && toDrop.length === 0) {
      console.log(`[db-init] Realtime publication OK (${REALTIME_TABLES.length} tables)`);
    } else {
      console.log(`[db-init] Realtime publication: +${missing.length} added, -${toDrop.length} dropped (final: ${REALTIME_TABLES.length} tables)`);
      if (missing.length > 0) console.log(`[db-init]   added: ${missing.join(", ")}`);
      if (toDrop.length > 0) console.log(`[db-init]   dropped: ${toDrop.join(", ")}`);
    }
  } catch (e) {
    console.warn("[db-init] Realtime publication check skipped:", e.message);
  }
}
async function nominatimReverseGeocode(lat, lng) {
  try {
    const url = `https://nominatim.openstreetmap.org/reverse?format=json&lat=${lat}&lon=${lng}&zoom=18&addressdetails=1`;
    const resp = await fetch(url, { headers: { "User-Agent": "TorresVP/1.0" }, signal: AbortSignal.timeout(5e3) });
    if (!resp.ok) return null;
    const data = await resp.json();
    if (!data || !data.address) return null;
    const a = data.address;
    const road = a.road || a.highway || a.pedestrian || "";
    const number = a.house_number || "";
    const suburb = a.suburb || a.neighbourhood || "";
    const city = a.city || a.town || a.municipality || a.county || "";
    const state2 = a.state || "";
    const stateCode = state2.length === 2 ? state2 : {
      "S\xE3o Paulo": "SP",
      "Rio de Janeiro": "RJ",
      "Minas Gerais": "MG",
      "Bahia": "BA",
      "Paran\xE1": "PR",
      "Rio Grande do Sul": "RS",
      "Pernambuco": "PE",
      "Cear\xE1": "CE",
      "Par\xE1": "PA",
      "Maranh\xE3o": "MA",
      "Santa Catarina": "SC",
      "Goi\xE1s": "GO",
      "Para\xEDba": "PB",
      "Esp\xEDrito Santo": "ES",
      "Amazonas": "AM",
      "Rio Grande do Norte": "RN",
      "Alagoas": "AL",
      "Piau\xED": "PI",
      "Mato Grosso": "MT",
      "Mato Grosso do Sul": "MS",
      "Distrito Federal": "DF",
      "Sergipe": "SE",
      "Rond\xF4nia": "RO",
      "Tocantins": "TO",
      "Acre": "AC",
      "Amap\xE1": "AP",
      "Roraima": "RR"
    }[state2] || state2;
    let parts = [];
    if (road) parts.push(number ? `${road}, ${number}` : road);
    if (suburb && !road.includes(suburb)) parts.push(suburb);
    if (city) parts.push(`${city}/${stateCode}`);
    return parts.length > 0 ? parts.join(", ") : data.display_name || null;
  } catch {
    return null;
  }
}
async function nominatimGeocode(address) {
  try {
    const url = `https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(address)}&countrycodes=br&limit=1`;
    const resp = await fetch(url, { headers: { "User-Agent": "TorresVP/1.0" }, signal: AbortSignal.timeout(5e3) });
    if (!resp.ok) return null;
    const data = await resp.json();
    if (data.length > 0) return { lat: parseFloat(data[0].lat), lng: parseFloat(data[0].lon) };
    const cityMatch = address.match(/,\s*([^,]+?)\s*-\s*([A-Z]{2})\s*,?\s*Brasil/i);
    if (cityMatch) {
      const simpler = `${cityMatch[1].trim()}, ${cityMatch[2]}, Brasil`;
      await new Promise((r) => setTimeout(r, 1100));
      const url2 = `https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(simpler)}&countrycodes=br&limit=1`;
      const resp2 = await fetch(url2, { headers: { "User-Agent": "TorresVP/1.0" }, signal: AbortSignal.timeout(5e3) });
      if (!resp2.ok) return null;
      const data2 = await resp2.json();
      if (data2.length > 0) {
        console.log(`[geocode] Fallback OK: "${address}" \u2192 "${simpler}" (${data2[0].lat},${data2[0].lon})`);
        return { lat: parseFloat(data2[0].lat), lng: parseFloat(data2[0].lon) };
      }
    }
    return null;
  } catch {
    return null;
  }
}
async function backfillOrderCoords() {
  const { data: ordersRaw } = await supabaseAdmin.from("service_orders").select("id, os_number, origin, destination, origin_lat, destination_lat").in("status", ["em_andamento", "agendada"]).or("origin_lat.is.null,destination_lat.is.null");
  const orders = toCamelArray(ordersRaw || []);
  if (orders.length === 0) return;
  console.log(`[db-init] Backfilling coordinates for ${orders.length} order(s)...`);
  for (const o of orders) {
    const updates = {};
    if (!o.originLat && o.origin) {
      const geo = await nominatimGeocode(o.origin);
      if (geo) {
        updates.originLat = geo.lat;
        updates.originLng = geo.lng;
      }
      await new Promise((r) => setTimeout(r, 1100));
    }
    if (!o.destinationLat && o.destination) {
      const geo = await nominatimGeocode(o.destination);
      if (geo) {
        updates.destinationLat = geo.lat;
        updates.destinationLng = geo.lng;
      }
      await new Promise((r) => setTimeout(r, 1100));
    }
    if (Object.keys(updates).length > 0) {
      const snakeUpdates = {};
      if (updates.originLat !== void 0) snakeUpdates.origin_lat = updates.originLat;
      if (updates.originLng !== void 0) snakeUpdates.origin_lng = updates.originLng;
      if (updates.destinationLat !== void 0) snakeUpdates.destination_lat = updates.destinationLat;
      if (updates.destinationLng !== void 0) snakeUpdates.destination_lng = updates.destinationLng;
      await supabaseAdmin.from("service_orders").update(snakeUpdates).eq("id", o.id);
      console.log(`[db-init] Geocoded ${o.osNumber}: origin=${updates.originLat ? "OK" : "skip"} dest=${updates.destinationLat ? "OK" : "skip"}`);
    }
  }
}
