      const emailValido = (e) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(e);
      if (emails.length === 0 || !emails.every(emailValido)) {
        return res.status(400).json({ message: "Informe um e-mail v\xE1lido (separe v\xE1rios por v\xEDrgula)." });
      }
