        return res.status(409).json({ message: "Esta fatura n\xE3o est\xE1 com NF em erro \u2014 reprocessar n\xE3o \xE9 permitido para evitar emiss\xE3o duplicada. Cancele a NF atual primeiro, se necess\xE1rio." });
