import PDFDocument from "pdfkit";
var COMPANY = {
  name: "TORRES VIGIL\xC2NCIA PATRIMONIAL LTDA",
  shortName: "TORRES VIGIL\xC2NCIA PATRIMONIAL",
  cnpj: "36.982.392/0001-89",
  city: "S\xE3o Paulo",
  state: "SP",
  footer: "www.torresseguranca.com.br \u2022 @grupotorres.seguranca \u2022 (11) 96369-6699 \u2022 escolta@torresseguranca.com.br"
};
function generateContractPDF(res, data) {
  const doc = new PDFDocument({
    size: "A4",
    margins: { top: 80, bottom: 70, left: 60, right: 60 },
    bufferPages: true
  });
  res.setHeader("Content-Type", "application/pdf");
  const safeName = data.clientName.replace(/[^a-zA-Z0-9 ]/g, "").replace(/\s+/g, "_");
  res.setHeader("Content-Disposition", `attachment; filename="Contrato_Escolta_${safeName}.pdf"`);
  doc.pipe(res);
  const W = doc.page.width - doc.page.margins.left - doc.page.margins.right;
  const LM = doc.page.margins.left;
  const INDENT = 20;
  const dateStr = data.contractDate || (/* @__PURE__ */ new Date()).toLocaleDateString("pt-BR", {
    day: "numeric",
    month: "long",
    year: "numeric"
  });
  const dateRaw = data.contractDate || (/* @__PURE__ */ new Date()).toLocaleDateString("pt-BR", { day: "2-digit", month: "2-digit", year: "numeric" });
  const dateParts = dateRaw.match(/(\d+)\s+de\s+(\w+)\s+de\s+(\d+)/);
  let vigenciaInicio = "";
  let vigenciaFim = "";
  if (dateParts) {
    vigenciaInicio = `${dateParts[1]}/${dateParts[2] === "janeiro" ? "01" : dateParts[2] === "fevereiro" ? "02" : dateParts[2] === "mar\xE7o" ? "03" : dateParts[2] === "abril" ? "04" : dateParts[2] === "maio" ? "05" : dateParts[2] === "junho" ? "06" : dateParts[2] === "julho" ? "07" : dateParts[2] === "agosto" ? "08" : dateParts[2] === "setembro" ? "09" : dateParts[2] === "outubro" ? "10" : dateParts[2] === "novembro" ? "11" : "12"}/${dateParts[3]}`;
    const y = parseInt(dateParts[3]) + 1;
    vigenciaFim = vigenciaInicio.replace(`/${dateParts[3]}`, `/${y}`);
  } else {
    const now = /* @__PURE__ */ new Date();
    const pad = (n2) => String(n2).padStart(2, "0");
    vigenciaInicio = `${pad(now.getDate())}/${pad(now.getMonth() + 1)}/${now.getFullYear()}`;
    vigenciaFim = `${pad(now.getDate())}/${pad(now.getMonth() + 1)}/${now.getFullYear() + 1}`;
  }
  const F_NORMAL = "Helvetica";
  const F_BOLD = "Helvetica-Bold";
  const F_ITALIC = "Helvetica-Oblique";
  const SZ = 10;
  const SZ_SM = 9;
  const SZ_TITLE = 14;
  const SZ_SUBTITLE = 11;
  const LG = 4;
  function drawHeader() {
    const y = 25;
    doc.font(F_BOLD).fontSize(10).fillColor("#000000");
    doc.text(COMPANY.shortName, LM, y, { width: W, align: "center" });
    doc.font(F_NORMAL).fontSize(8).fillColor("#555555");
    doc.text(`CNPJ: ${COMPANY.cnpj}`, LM, y + 14, { width: W, align: "center" });
    doc.fillColor("#000000");
  }
  function drawFooter(pageNum, totalPages2) {
    const y = doc.page.height - 45;
    doc.font(F_NORMAL).fontSize(7).fillColor("#555555");
    doc.text(COMPANY.footer, LM, y, { width: W, align: "center", lineBreak: false });
    doc.fillColor("#000000");
  }
  function checkPage(needed = 60) {
    if (doc.y + needed > doc.page.height - doc.page.margins.bottom - 10) {
      doc.addPage();
      drawHeader();
      doc.y = 65;
    }
  }
  function clauseTitle(text2) {
    checkPage(35);
    doc.moveDown(0.6);
    doc.font(F_BOLD).fontSize(SZ).text(` ${text2}`, LM, doc.y, { lineGap: LG });
    doc.moveDown(0.4);
  }
  function body(text2) {
    checkPage(25);
    doc.font(F_NORMAL).fontSize(SZ).text(text2, LM, doc.y, {
      align: "justify",
      lineGap: LG,
      width: W
    });
    doc.moveDown(0.3);
  }
  function sub(num2, text2) {
    checkPage(25);
    doc.font(F_NORMAL).fontSize(SZ_SM).text(`${num2} - ${text2}`, LM + INDENT, doc.y, {
      align: "justify",
      lineGap: 3,
      width: W - INDENT
    });
    doc.moveDown(0.2);
  }
  drawHeader();
  doc.y = 65;
  doc.moveDown(1.5);
  doc.font(F_BOLD).fontSize(SZ_TITLE).text("MINUTA DE CONTRATO", { align: "center" });
  doc.font(F_BOLD).fontSize(SZ_SUBTITLE).text("PRESTA\xC7\xC3O DE SERVI\xC7OS DE ESCOLTA ARMADA", { align: "center" });
  doc.moveDown(1.5);
  doc.font(F_BOLD).fontSize(SZ).text("CONTRATANTE: ", { continued: true });
  doc.font(F_NORMAL).text(
    `${data.clientName}. Pessoa jur\xEDdica de direito privado, inscrita no CNPJ/MF sob n\xBA ${data.clientCnpj}, com sede fiscal na ${data.clientAddress}, ${data.clientCity}, ${data.clientState}, ${data.clientZip}, representado neste ato por ${data.clientContact}.`,
    { align: "justify", lineGap: LG }
  );
  doc.moveDown(0.6);
  doc.font(F_BOLD).fontSize(SZ).text("CONTRATADA: ", { continued: true });
  doc.font(F_NORMAL).text(
    `${COMPANY.name}. Pessoa jur\xEDdica de direito privado, inscrita no CNPJ/MF sob n\xBA ${COMPANY.cnpj}, com sede fiscal em ${COMPANY.city}/${COMPANY.state}.`,
    { align: "justify", lineGap: LG }
  );
  doc.moveDown(0.5);
  body("As partes, acima nomeadas e qualificadas, t\xEAm entre si como justo e acordado o presente Contrato de Presta\xE7\xE3o de Servi\xE7os de Escolta Armada, que se reger\xE3o pelos termos, cl\xE1usulas, obriga\xE7\xF5es e condi\xE7\xF5es adiante articuladas:");
  doc.moveDown(0.3);
  clauseTitle("Cl\xE1usula 1 \u2013 Do Objeto");
  body("A CONTRATADA prestar\xE1 \xE0 CONTRATANTE os servi\xE7os especializados de Escolta Armada, atrav\xE9s do acompanhamento ostensivo de caminh\xF5es e ve\xEDculos de carga, denominados auto cargas, que transportam mercadorias consideradas de alto risco, quanto a roubos e furtos, conforme discrimina\xE7\xE3o contida no Quadro Resumo, que fica fazendo parte integrante deste instrumento.");
  sub("1.1", "A seguran\xE7a ser\xE1 realizada atrav\xE9s do acompanhamento ostensivo de caminh\xF5es e ve\xEDculos de carga, em vias p\xFAblicas em geral, contando com o apoio de Viaturas de Escolta, devidamente identificadas com o bras\xE3o da CONTRATADA, equipadas com sistema de r\xE1dio comunica\xE7\xE3o e dotadas de 04 (quatro) portas, podendo ser inclusive rastreadas via sat\xE9lite.");
  sub("1.2", "Os servi\xE7os de Escolta Armada ser\xE3o prestados por vigilantes identificados atrav\xE9s de crach\xE1 de identifica\xE7\xE3o, treinados, uniformizados, armados e munidos de equipamentos e materiais indispens\xE1veis \xE0 execu\xE7\xE3o dos servi\xE7os, definidos e discriminados na Cl\xE1usula 6 abaixo, obedecida a legisla\xE7\xE3o vigente e as tratativas entre as partes.");
  clauseTitle("Cl\xE1usula 2 \u2013 Do Quadro Resumo");
  body("As partes acordam que o Quadro Resumo, parte integrante do presente instrumento, definir\xE1 todos os aspectos operacionais, t\xE9cnicos e financeiros dos servi\xE7os a serem prestados pela CONTRATADA \xE0 CONTRATANTE.");
  clauseTitle("Cl\xE1usula 3 \u2013 Dos Documentos Integrantes");
  body("Para melhor caracteriza\xE7\xE3o do objeto deste CONTRATO, bem como para definir procedimentos decorrentes das obriga\xE7\xF5es ora contra\xEDdos, integram este instrumento, como se nele estivessem transcritos, os dispositivos pertinentes \xE0s normas de seguran\xE7a; as atas; as correspond\xEAncias entre as partes, \xE0s trocadas e as futuras, e, mais, os documentos t\xE9cnicos dos servi\xE7os solicitados.");
  clauseTitle("Cl\xE1usula 4 \u2013 Das Altera\xE7\xF5es dos Servi\xE7os");
  body("Os servi\xE7os prestados poder\xE3o sofrer altera\xE7\xF5es, desde que, antecipadamente, sejam submetidos \xE0 an\xE1lise da CONTRATANTE, atrav\xE9s de correspond\xEAncia pr\xF3pria enviada pela CONTRATADA, levando-se em conta que tais altera\xE7\xF5es ocorram para melhor adequ\xE1-los em raz\xE3o de operacionalidade e/ou prioridades.");
  clauseTitle("Cl\xE1usula 5 \u2013 Da Individualiza\xE7\xE3o dos Servi\xE7os");
  body("Os servi\xE7os a serem prestados pela CONTRATADA \xE0 CONTRATANTE est\xE3o descritos e individualizados no Quadro Resumo anexo, que faz parte integrante deste instrumento.");
  clauseTitle("Cl\xE1usula 6 \u2013 Dos Vigilantes, Do Armamento e Dos Equipamentos Indispens\xE1veis \xE0 Execu\xE7\xE3o dos Servi\xE7os");
  body("Os vigilantes, o armamento e os equipamentos indispens\xE1veis \xE0 execu\xE7\xE3o dos servi\xE7os de Escolta Armada ser\xE3o fornecidos pela contratada, sendo todos de sua responsabilidade e patrim\xF4nio.");
  sub("6.1", "A contratada disponibilizar\xE1 02 (Dois) Vigilantes de Escolta Armada por opera\xE7\xE3o.");
  sub("6.2", "A contratada disponibilizar\xE1 para cada opera\xE7\xE3o:");
  sub("6.2.1", "01 (um) Rev\xF3lver Calibre 38 de 5 (cinco) ou de 6 (seis) tiros;");
  sub("6.2.2", "01 (uma) Espingarda Calibre 12 Pistol Grip, tipo Pump ou similar;");
  sub("6.2.3", "12 (doze) cartuchos de muni\xE7\xE3o calibre 38, sendo 6 (seis) cartuchos empregados no municiamento da arma e 6 (seis) no carregador adicional;");
  sub("6.2.4", "02 (dois) Coletes \xE0 prova de bala n\xEDvel II-A;");
  sub("6.2.5", "14 (quatorze) Cartuchos de muni\xE7\xE3o calibre 12, sendo 07 (sete) empregados no municiamento da arma e 07 (sete) armazenados em estojo para municiamento adicional;");
  sub("6.2.6", "01 (um) R\xE1dio transceptor para comunica\xE7\xE3o entre a equipe, a base e se for o caso entre a contratante;");
  sub("6.2.7", "01 (um) ve\xEDculo (viatura) de passageiros com capacidade para 5 (cinco) ocupantes, motor 1.0 ou superior, com 4 (quatro) portas, preferencialmente com menos de 2 (dois) anos de uso e/ou fabrica\xE7\xE3o, devidamente identificada com o bras\xE3o da empresa e demais elementos de identifica\xE7\xE3o de escolta armada e contatos da empresa, equipado com sistema de rastreamento de ve\xEDculo tipo satelital e com 2 (dois) bot\xF5es de p\xE2nico a ser acionado em casos de emerg\xEAncias e/ou ocorr\xEAncias durante a opera\xE7\xE3o;");
  sub("6.3", "A contratada fornecer\xE1 a seus funcion\xE1rios envolvidos na presta\xE7\xE3o dos servi\xE7os conjuntos completos de uniforme, sendo capote, cal\xE7a terbrim cor preta, camisa terbrim cor preta com bras\xE3o de identifica\xE7\xE3o, boina feltro preta, coturnos de cano de lona preta, cord\xE3o fiel, coldre de arma com cinto modelo robocop, cinto de lona para cal\xE7as e capa de colete.");
  clauseTitle("Cl\xE1usula 7 \u2013 Do Prazo de Vig\xEAncia");
  body(`O prazo de vig\xEAncia deste contrato \xE9 de ${vigenciaInicio} a ${vigenciaFim}, sendo que, qualquer das partes poder\xE1 rescindi-lo, a qualquer momento, desde que, notifique a outra, com pr\xE9via anteced\xEAncia de 30 (trinta) dias.`);
  clauseTitle("Cl\xE1usula 8 \u2013 Do Pre\xE7o");
  body("Os valores inerentes \xE0s opera\xE7\xF5es de Escolta Armada ser\xE3o cobrados conforme o destino da miss\xE3o, o tempo do deslocamento, os pernoites e os servi\xE7os de preserva\xE7\xE3o, podendo estas ser Urbanas ou Rodovi\xE1rias dentro da Regi\xE3o da Grande S\xE3o Paulo ou Opera\xE7\xF5es Estaduais ou Interestaduais, desde que estas se iniciem no Estado de S\xE3o Paulo; de forma tal que a cada evento de escolta ser\xE1 tratado individualmente e seus custos previamente acordados, sendo estes, descritos no Anexo I.");
  sub("8.1", "O valor dos servi\xE7os contratados ser\xE1 pago nas datas, condi\xE7\xF5es e periodicidade constantes da Cl\xE1usula 9, abaixo.");
  sub("8.2", "A CONTRATANTE ser\xE1 considerada inadimplente, caso deixe de pagar, na data de vencimento normal da obriga\xE7\xE3o, o valor dos servi\xE7os prestados, constituindo tal fato motivo justo para a rescis\xE3o contratual pela CONTRATADA, cabendo ainda a esta o direito de cobrar seu cr\xE9dito, com os acr\xE9scimos constantes do item seguinte.");
  sub("8.3", "No pre\xE7o do servi\xE7o ajustado n\xE3o est\xE3o computados qualquer expectativa inflacion\xE1ria, raz\xE3o pela qual sobre os pagamentos vincendos n\xE3o se aplicar\xE3o qualquer \xEDndice deflacion\xE1rio e/ou congelamento e/ou restri\xE7\xF5es de atualiza\xE7\xE3o monet\xE1ria, tais como, exemplificativamente, tablitas, deflatores, planos econ\xF4micos de governo etc.");
  clauseTitle("Cl\xE1usula 9 \u2013 Do Faturamento dos Servi\xE7os e Forma de Pagamento");
  body("O pagamento ser\xE1 efetuado pela CONTRATANTE \xE0 CONTRATADA posterior a execu\xE7\xE3o do servi\xE7o prestado, conforme acordado entre as partes.");
  sub("9.1", "Os servi\xE7os que ultrapassarem a carga hor\xE1ria contratada, ou seja, o tempo predeterminado por miss\xE3o ser\xE1 cobrado horas adicionais, com o valor acordado entre as partes, da mesma forma os servi\xE7os que ultrapassarem a quilometragem contratada, ou seja, a dist\xE2ncia predeterminada por miss\xE3o ser\xE1 cobrado quil\xF4metros adicionais, com o valor acordado entre as partes, conforme ANEXO I; ficando aven\xE7ado que os valores correspondentes \xE0 presta\xE7\xE3o destes servi\xE7os ser\xE3o totalizados e faturados conforme caput da Cl\xE1usula 9 deste contrato.");
  clauseTitle("Cl\xE1usula 10 \u2013 Da Altera\xE7\xE3o de Pre\xE7os");
  sub("10.1", "Os pre\xE7os estabelecidos no presente contrato ser\xE3o atualizados por eventuais aumentos advindos de custos setoriais, equipamentos, materiais e, especialmente, aqueles relacionados com os reajustes dos empregados da CONTRATADA, provenientes de Acordo ou Diss\xEDdio Coletivo da Categoria, bem como novos encargos, taxas ou tributos criados pelo Poder P\xFAblico Federal, Estadual ou Municipal, que impactem a planilha de composi\xE7\xE3o de pre\xE7os da CONTRATADA, ensejar\xE3o uma atualiza\xE7\xE3o dos pre\xE7os contratuais, mediante pr\xE9via comunica\xE7\xE3o escrita da CONTRATADA \xE0 CONTRATANTE e mediante pr\xE9vio acordo entre as partes.");
  sub("10.2", "Fica previamente acordado entre as partes que, caso ocorra uma eleva\xE7\xE3o desproporcional dos \xEDndices de custeio deste contrato, em fun\xE7\xE3o de reajustes dos custos diretos e indiretos, haver\xE1 uma negocia\xE7\xE3o entre as partes, visando a readequa\xE7\xE3o dos pre\xE7os contratuais, a fim de que se recomponha o equil\xEDbrio econ\xF4mico-financeiro do contrato.");
  clauseTitle("Cl\xE1usula 11 \u2013 Da Rescis\xE3o Contratual");
  sub("11.1", "O presente contrato poder\xE1 ser rescindido, sem a incid\xEAncia de multa, por qualquer das partes, mediante pr\xE9vio aviso, por escrito, com anteced\xEAncia m\xEDnima de 30 (trinta) dias, contados da data em que a outra parte receber a aludida comunica\xE7\xE3o, devidamente protocolizada.");
  clauseTitle("Cl\xE1usula 12 \u2013 Da Responsabilidade das Partes");
  body("A CONTRATADA \xE9 respons\xE1vel, direta e exclusiva, pela execu\xE7\xE3o integral dos servi\xE7os objeto do presente contrato, bem como por eventuais danos, que por si, seus prepostos, empregados, por dolo ou culpa, causarem \xE0 CONTRATANTE, desde que devidamente comprovados e comunicados por escrito, pela CONTRATANTE \xE0 CONTRATADA, at\xE9 o segundo dia \xFAtil posterior \xE0 ocorr\xEAncia.");
  sub("12.1", "A CONTRATADA compromete-se a utilizar, na presta\xE7\xE3o dos servi\xE7os, profissionais previamente selecionados, sem antecedentes criminais e pol\xEDtico-sociais, bem como profissionais que melhor se adaptem \xE0s caracter\xEDsticas exigidas pela CONTRATANTE.");
  sub("12.2", "Os servi\xE7os de escolta armada ser\xE3o prestados por vigilantes treinados, uniformizados, equipados e armados, sempre de comum acordo entre as partes e em conformidade com a Lei n\xBA 7.102, de 20/06/83 e a Lei n\xBA 9.017, de 30/03/95.");
  sub("12.3", "A CONTRATADA fica assegurada no direito de promover substitui\xE7\xF5es, quando necess\xE1rio, de vigilantes e outros elementos destacados para os servi\xE7os aqui descritos e contratado sendo dever da CONTRATADA, promover a substitui\xE7\xE3o imediatamente ap\xF3s comunica\xE7\xE3o por escrito da CONTRATANTE, qualquer de seus empregados ou prepostos cuja perman\xEAncia nos locais de presta\xE7\xE3o de servi\xE7o for julgada inconveniente.");
  sub("12.4", "A CONTRATADA n\xE3o ser\xE1 respons\xE1vel por eventos decorrentes de defici\xEAncia operacional, se esta for proveniente de altera\xE7\xF5es de ordens ou rotinas dadas unilateralmente pela CONTRATANTE aos vigilantes e prepostos da CONTRATADA.");
  sub("12.5", "Fica entendido entre as partes contratantes que, ao vigilante, n\xE3o se deve dar incumb\xEAncia fora de suas atividades espec\xEDficas.");
  sub("12.6", "A CONTRATADA manter\xE1 um servi\xE7o de inspe\xE7\xE3o de seus vigilantes e prepostos, verificando periodicamente, o andamento dos servi\xE7os e procedimentos de seguran\xE7a, sem que isto implique em quaisquer \xF4nus ou acr\xE9scimo no pre\xE7o pago pela CONTRATANTE.");
  clauseTitle("Cl\xE1usula 13 \u2013 Dos Ressarcimentos e Reembolsos");
  body("Correr\xE3o por conta exclusiva da CONTRATANTE, todas as despesas referentes a ped\xE1gios em estradas estaduais e federais, bem como estadias e despesas em viagens, quando as mesmas forem decorrentes de despesas extraordin\xE1rias para os servi\xE7os previamente acordados, desde que as mesmas sejam devidamente autorizadas pela CONTRATANTE, devendo, referidas despesas, ser ressarcidas ou reembolsadas, mediante a apresenta\xE7\xE3o, por parte da CONTRATADA, dos respectivos comprovantes e/ou notas fiscais referentes aos desembolsos.");
  clauseTitle("Cl\xE1usula 14 \u2013 Das Omiss\xF5es do Contrato");
  body("Quaisquer fatos ou casos omissos no presente contrato n\xE3o ensejar\xE3o a sua rescis\xE3o.");
  sub("14.1", "O presente contrato obriga as partes, por si, seus herdeiros e sucessores, a qualquer t\xEDtulo.");
  sub("14.2", "Qualquer altera\xE7\xE3o ou modifica\xE7\xE3o \xE0s cl\xE1usulas e condi\xE7\xF5es deste contrato somente ser\xE1 v\xE1lida se feita por documento escrito, assinado pelas partes e testemunhas, que se constituir\xE1 em aditivo ao presente.");
  clauseTitle("Cl\xE1usula 15 \u2013 Da Exclus\xE3o do V\xEDnculo Empregat\xEDcio");
  body("O presente contrato, em raz\xE3o do seu objetivo e natureza, n\xE3o gera para a CONTRATANTE, em rela\xE7\xE3o aos empregados e prepostos da CONTRATADA, qualquer v\xEDnculo de natureza trabalhista e/ou previdenci\xE1ria, respondendo exclusivamente a CONTRATADA por toda e qualquer a\xE7\xE3o trabalhista e/ou indenizat\xF3ria por eles propostas, bem como pelo resultado delas.");
  clauseTitle("Cl\xE1usula 16 \u2013 Das Disposi\xE7\xF5es Gerais");
  sub("16.1", "A CONTRATADA somente ser\xE1 respons\xE1vel pela presta\xE7\xE3o dos servi\xE7os objeto deste contrato, n\xE3o podendo garantir a inocorr\xEAncia de fatos delituosos contra o patrim\xF4nio da CONTRATANTE ou de terceiros, nem responder pelo desaparecimento, furto, roubo, dano ou destrui\xE7\xE3o de quaisquer bens, cargas ou objetos de propriedade da CONTRATANTE ou de terceiros ou por qualquer outro dano ou preju\xEDzo que venha a ser causado \xE0 CONTRATANTE ou a terceiros que n\xE3o tenha sido causado diretamente pelos funcion\xE1rios e/ou preposto da CONTRATADA.");
  sub("16.2", "Fica convencionado que a CONTRATADA, em rela\xE7\xE3o aos seus funcion\xE1rios alocados na CONTRATANTE, se responsabiliza por quaisquer \xF4nus decorrentes de fiscaliza\xE7\xF5es realizadas pelo Minist\xE9rio do Trabalho e do Emprego, atrav\xE9s das Delegacias Regionais do Trabalho, tais como notifica\xE7\xF5es para apresenta\xE7\xE3o de documentos, registros de empregados, esclarecimentos, e outros que forem pertinentes \xE0 situa\xE7\xE3o, al\xE9m da apresenta\xE7\xE3o de defesas e recursos administrativos decorrentes de autua\xE7\xF5es fiscais, com o necess\xE1rio pagamento das multas administrativas impostas.");
  sub("16.3", '\xC9 vedado a qualquer das partes utilizar o presente objeto contratual em garantias para transa\xE7\xF5es banc\xE1rias e/ou financeiras de qualquer esp\xE9cie, efetuar opera\xE7\xE3o de desconto, negociar, repassar ou de qualquer forma ceder os cr\xE9ditos decorrentes da execu\xE7\xE3o desse a Bancos, empresas de "factoring" ou terceiros, sem pr\xE9via autoriza\xE7\xE3o por escrito da outra parte.');
  sub("16.4", "Ficam desde j\xE1 convencionados que o presente contrato n\xE3o ir\xE1 configurar nenhum outro direito para as partes, al\xE9m da presta\xE7\xE3o dos servi\xE7os supramencionados, devendo este contrato ser interpretado sob o ponto de vista restritivo, de modo a n\xE3o permitir qualquer interpreta\xE7\xE3o diferente da objetivada pelas partes.");
  sub("16.5", "Eventual toler\xE2ncia de uma parte a infra\xE7\xF5es ou descumprimento das condi\xE7\xF5es estipuladas no presente contrato, cometidas pela outra parte, ser\xE1 tida como ato de mera liberalidade, n\xE3o se constituindo em perd\xE3o, precedente, nova\xE7\xE3o ou ren\xFAncia a direitos que a legisla\xE7\xE3o ou o contrato assegurem \xE0s partes.");
  sub("16.6", "A assinatura do presente contrato representa a aceita\xE7\xE3o de todas as disposi\xE7\xF5es nele contidas, prevalecendo sobre todas as tratativas e entendimentos mantidos anteriormente entre as partes.");
  sub("16.7", "Se qualquer cl\xE1usula ou dispositivo deste contrato for considerado nulo ou sem efeito, no todo ou em parte, as demais dever\xE3o permanecer v\xE1lidas e ser\xE3o interpretadas de forma a preservar sua validade.");
  sub("16.8", "O presente contrato expressa todos os acordos e condi\xE7\xF5es estipulados pelas partes com rela\xE7\xE3o ao objeto contrato, substituindo todos os eventuais contratos e seus anexos anteriormente firmados entre elas, os quais neste ato s\xE3o tidos como rescindidos ofertando-se as partes m\xFAtua quita\xE7\xE3o para nada mais reclamar.");
  clauseTitle("Cl\xE1usula 17 \u2013 Do Sigilo");
  body("Toda e qualquer informa\xE7\xE3o relativa ao objeto do presente ser\xE1 sempre considerada sigilosa e confidencial, ficando expressamente vedado \xE0 CONTRATADA, bem como aos seus empregados ou prepostos, delas dar conhecimento a terceiros n\xE3o autorizados, sob pena de responsabiliza\xE7\xE3o civil e criminal.");
  clauseTitle("Cl\xE1usula 18 \u2013 Do Foro");
  body("As partes elegem o Foro Central de S\xE3o Paulo \u2013 SP para dirimir eventuais d\xFAvidas ou diverg\xEAncias que as partes venham a ter com rela\xE7\xE3o ao presente contrato. E, por estarem assim ajustadas, declaram as partes aceitar as disposi\xE7\xF5es estabelecidas nas cl\xE1usulas do presente contrato, que, ap\xF3s lido e achado conforme, vai assinado pelos representantes legais das partes e pelas testemunhas abaixo.");
  doc.moveDown(1.5);
  checkPage(250);
  doc.font(F_NORMAL).fontSize(SZ).text(`S\xE3o Paulo, ${dateStr}.`, { align: "center" });
  doc.moveDown(2);
  const colW = (W - 50) / 2;
  const leftCol = LM;
  const rightCol = LM + colW + 50;
  let sigY = doc.y;
  doc.save();
  doc.rect(leftCol, sigY, colW, 3).fill("#111111");
  doc.rect(rightCol, sigY, colW, 3).fill("#111111");
  doc.restore();
  sigY += 18;
  doc.font(F_BOLD).fontSize(9).fillColor("#000000");
  doc.text("CONTRATADA", leftCol, sigY, { width: colW, align: "center" });
  doc.text("CONTRATANTE", rightCol, sigY, { width: colW, align: "center" });
  sigY += 14;
  doc.font(F_NORMAL).fontSize(8);
  doc.text(COMPANY.name, leftCol, sigY, { width: colW, align: "center" });
  doc.text(data.clientName.toUpperCase(), rightCol, sigY, { width: colW, align: "center" });
  sigY += 12;
  doc.font(F_NORMAL).fontSize(7.5).fillColor("#666666");
  doc.text(`CNPJ: ${COMPANY.cnpj}`, leftCol, sigY, { width: colW, align: "center" });
  doc.text(`CNPJ: ${data.clientCnpj}`, rightCol, sigY, { width: colW, align: "center" });
  doc.fillColor("#000000");
  sigY += 28;
  doc.y = sigY;
  doc.save();
  doc.rect(leftCol, sigY, W, 20).fill("#111111");
  doc.restore();
  doc.font(F_BOLD).fontSize(9).fillColor("#FFFFFF");
  doc.text(" TESTEMUNHAS", leftCol + 6, sigY + 4, { width: W - 12 });
  doc.fillColor("#000000");
  sigY += 30;
  doc.font(F_BOLD).fontSize(SZ_SM);
  doc.text("Testemunha 1:", leftCol, sigY);
  sigY += 22;
  doc.font(F_NORMAL).fontSize(SZ_SM);
  doc.text("RG:   ______________________", leftCol, sigY);
  doc.text("CPF:     ______________________", rightCol, sigY);
  sigY += 26;
  doc.font(F_BOLD).fontSize(SZ_SM);
  doc.text("Testemunha 2:", leftCol, sigY);
  sigY += 22;
  doc.font(F_NORMAL).fontSize(SZ_SM);
  doc.text("RG:   ______________________", leftCol, sigY);
  doc.text("CPF:     ______________________", rightCol, sigY);
  doc.y = sigY + 20;
  const totalPages = doc.bufferedPageRange().count;
  for (let i = 0; i < totalPages; i++) {
    doc.switchToPage(i);
    if (i > 0) {
      drawHeader();
    }
    drawFooter(i + 1, totalPages);
  }
  doc.end();
}

// server/routes/clients.ts
init_zapi();
function registerClientRoutes(app2) {
  app2.get("/api/clients", requireAuth, requireAdminRole, async (_req, res) => {
    const data = await storage.getClients();
    res.json(data);
  });
  let groupsCache = null;
  const GROUPS_CACHE_TTL_MS = 6e4;
  app2.get("/api/whatsapp/groups", requireAuth, requireAdminRole, async (req, res) => {
    try {
      const bypassCache = req.query.refresh === "1" || req.query.refresh === "true";
      if (!bypassCache && groupsCache && Date.now() - groupsCache.ts < GROUPS_CACHE_TTL_MS) {
        return res.json({ ...groupsCache.payload, cached: true });
      }
      const r = await listGroups();
      const payload = {
        ok: r.ok,
        groups: r.groups,
        error: r.error || null,
        count: r.groups.length
      };
      console.log(`[whatsapp/groups] listGroups -> ok=${r.ok} count=${r.groups.length} error=${r.error || "-"} names=[${r.groups.slice(0, 5).map((g) => g.name).join(", ")}]`);
      if (r.ok) groupsCache = { ts: Date.now(), payload };
      res.json(payload);
    } catch (e) {
      res.status(500).json({ ok: false, groups: [], error: e?.message || "erro interno" });
    }
  });
  app2.get("/api/clients/:id", requireAuth, requireAdminRole, async (req, res) => {
    const data = await storage.getClient(Number(req.params.id));
    if (!data) return res.status(404).json({ message: "Cliente n\xE3o encontrado" });
    res.json(data);
  });
  app2.get("/api/clients/:id/contrato-pdf", requireAuth, async (req, res) => {
    try {
      const client = await storage.getClient(Number(req.params.id));
      if (!client) return res.status(404).json({ message: "Cliente n\xE3o encontrado" });
      const dateParam = req.query.date;
      let contractDate;
      if (dateParam) {
        const d = /* @__PURE__ */ new Date(dateParam + "T12:00:00");
        if (!isNaN(d.getTime())) {
          contractDate = d.toLocaleDateString("pt-BR", { day: "numeric", month: "long", year: "numeric" });
        }
      }
      generateContractPDF(res, {
        clientName: client.name,
        clientCnpj: client.cnpj || "_______________",
        clientAddress: client.address || "_______________",
        clientCity: client.city || "_______________",
        clientState: client.state || "__",
        clientZip: client.zip || "________",
        clientContact: client.contactPerson || "_______________",
        contractDate
      });
    } catch (err) {
      console.error("[Contract PDF] Error:", err);
      if (!res.headersSent) res.status(500).json({ message: "Erro ao gerar contrato" });
    }
  });
  app2.post("/api/clients", requireAuth, requireAdminRole, async (req, res) => {
    const parsed = insertClientSchema.safeParse(req.body);
    if (!parsed.success) return res.status(400).json({ message: "Dados inv\xE1lidos", errors: parsed.error.errors });
    const contactErrors = validateContactFields(parsed.data, { phones: ["phone"], zips: ["zip"] });
    if (contactErrors.length) return res.status(400).json({ message: contactErrors[0].message, errors: contactErrors });
    const data = await storage.createClient(parsed.data);
    const doc = data.cnpj || data.cpf || "";
    if (doc.replace(/\D/g, "").length >= 11) {
      autoConsultaCliente(doc, req.user.id).catch(() => {
      });
    }
    res.status(201).json(data);
  });
  app2.patch("/api/clients/:id", requireAuth, requireAdminRole, async (req, res) => {
    const parsed = insertClientSchema.partial().safeParse(req.body);
    if (!parsed.success) return res.status(400).json({ message: "Dados inv\xE1lidos", errors: parsed.error.errors });
    const contactErrors = validateContactFields(parsed.data, { phones: ["phone"], zips: ["zip"] });
    if (contactErrors.length) return res.status(400).json({ message: contactErrors[0].message, errors: contactErrors });
    try {
      const data = await storage.updateClient(Number(req.params.id), parsed.data);
      if (!data) return res.status(404).json({ message: "Cliente n\xE3o encontrado" });
      res.json(data);
    } catch (err) {
      console.error(`[clients PATCH ${req.params.id}] erro ao salvar:`, err.message);
      res.status(500).json({ message: err.message || "Erro ao salvar cliente" });
    }
  });
  app2.delete("/api/clients/:id", requireAuth, requireDiretoria, async (req, res) => {
    const clientId = Number(req.params.id);
    try {
      await supabaseAdmin.from("client_vehicles").delete().eq("client_id", clientId);
      await storage.deleteClient(clientId);
      res.json({ message: "Cliente removido" });
    } catch (err) {
      console.error("Erro ao remover cliente:", err.message);
      res.status(500).json({ message: "Erro ao remover. Existem OS ou contratos vinculados a este cliente." });
    }
  });
  app2.get("/api/clients/:id/vehicles", requireAuth, requireAdminRole, async (req, res) => {
    const data = await storage.getClientVehicles(Number(req.params.id));
    res.json(data);
  });
  app2.post("/api/clients/:id/vehicles", requireAuth, requireAdminRole, async (req, res) => {
    const clientId = Number(req.params.id);
    const { plate, model, brand, color, driverName, driverPhone, notes } = req.body;
    if (!plate) return res.status(400).json({ message: "Placa \xE9 obrigat\xF3ria" });
    const existing = await storage.getClientVehicleByPlate(clientId, plate);
    if (existing) return res.status(409).json({ message: "Placa j\xE1 cadastrada para este cliente", vehicle: existing });
    const data = await storage.createClientVehicle({ clientId, plate: plate.toUpperCase(), model, brand, color, driverName, driverPhone, notes });
    res.status(201).json(data);
  });
  app2.patch("/api/client-vehicles/:id", requireAuth, requireAdminRole, async (req, res) => {
    const existing = await storage.getClientVehicle(Number(req.params.id));
    if (!existing) return res.status(404).json({ message: "Ve\xEDculo n\xE3o encontrado" });
    if (req.body.plate && req.body.plate.toUpperCase() !== existing.plate) {
      const dup = await storage.getClientVehicleByPlate(existing.clientId, req.body.plate.toUpperCase());
      if (dup) return res.status(400).json({ message: "Placa j\xE1 cadastrada para este cliente" });
    }
    const data = await storage.updateClientVehicle(Number(req.params.id), req.body);
    res.json(data);
  });
  app2.delete("/api/client-vehicles/:id", requireAuth, requireDiretoria, async (req, res) => {
    await storage.deleteClientVehicle(Number(req.params.id));
    res.json({ message: "Ve\xEDculo removido" });
  });
  app2.get("/api/clients/:id/billing-config", requireAuth, requireAdminRole, async (req, res) => {
    try {
      const { id } = req.params;
      const { data, error } = await supabaseAdmin.from("clients").select("billing_cycle, payment_terms_days, billing_cutoff_day").eq("id", id).single();
      if (error) throw error;
      res.json(data || {});
    } catch (err) {
      res.status(500).json({ message: err.message });
    }
  });
}

