      const merged = { ...DEFAULT_PROBATION_TEMPLATE, ...incoming };
      const value = JSON.stringify(merged);
      const { data: existing } = await supabaseAdmin.from("system_settings").select("id").eq("key", "probation_contract_template").limit(1);
      if (!existing?.length) {
        await supabaseAdmin.from("system_settings").insert({ key: "probation_contract_template", value });
      } else {
        await supabaseAdmin.from("system_settings").update({ value, updated_at: (/* @__PURE__ */ new Date()).toISOString() }).eq("key", "probation_contract_template");
      }
