var FUELING_MAX_KM_JUMP = 1500;
function validateFuelingKm(kmRaw, vehicleKmRaw, allowKmOverride) {
  const km = Number(kmRaw) || 0;
  const vehicleKm = Number(vehicleKmRaw) || 0;
  if (km < vehicleKm) {
    if (allowKmOverride) return null;
    return {
      reason: "lower",
      message: `KM informado (${km}) \xE9 menor que o KM atual do ve\xEDculo (${vehicleKm}). Verifique o hod\xF4metro.`
    };
  }
  if (vehicleKm > 0 && km >= vehicleKm) {
    const kmDiff = km - vehicleKm;
    if (kmDiff > FUELING_MAX_KM_JUMP) {
      return {
        reason: "jump",
        message: `KM informado (${km}) \xE9 ${kmDiff} km a mais que o KM atual (${vehicleKm}). Diferen\xE7a muito grande \u2014 verifique o hod\xF4metro.`
      };
    }
  }
  return null;
}
