  app2.post("/api/mission/update", requireAuth, async (req, res) => {
    const user = req.user;
    if (!user.employeeId) return res.status(403).json({ message: "Usu\xE1rio n\xE3o \xE9 funcion\xE1rio" });
    const { serviceOrderId, message, missionStep, latitude, longitude, photoUrl } = req.body;
    if (!serviceOrderId || !message?.trim()) {
      return res.status(400).json({ message: "OS e mensagem s\xE3o obrigat\xF3rios" });
    }
    let validatedPhotoUrl = null;
    if (photoUrl && typeof photoUrl === "string" && photoUrl.startsWith("data:image/") && photoUrl.length <= 10 * 1024 * 1024) {
      try {
        validatedPhotoUrl = await uploadMissionPhoto(serviceOrderId, photoUrl);
      } catch (e) {
        console.error("[mission-update] upload foto falhou, fallback base64:", e?.message);
        validatedPhotoUrl = photoUrl;
      }
    }
    const so = await storage.getServiceOrder(serviceOrderId);
    if (!so) return res.status(404).json({ message: "OS n\xE3o encontrada" });
    const isAdminLike = ["admin", "supervisor", "operacao", "opera\xE7\xE3o", "diretoria"].includes(
      String(user.role || "").toLowerCase()
    );
    const isAssigned = so.assignedEmployeeId === user.employeeId || so.assignedEmployee2Id === user.employeeId;
    if (!isAdminLike && !isAssigned) {
      return res.status(403).json({ message: "Funcion\xE1rio n\xE3o est\xE1 vinculado a esta OS" });
    }
    const emp = await storage.getEmployee(user.employeeId);
    try {
      const { correctAgentMessage: correctAgentMessage2 } = await Promise.resolve().then(() => (init_correct_text_ai(), correct_text_ai_exports));
      const correctedMessage = await correctAgentMessage2(message.trim());
      const resolvedMissionStep = missionStep || so.missionStatus || null;
      const { error: insertError } = await supabaseAdmin.from("mission_updates").insert({
        service_order_id: serviceOrderId,
        os_number: so.osNumber || null,
        employee_id: user.employeeId,
        employee_name: emp?.name || user.name || "\u2014",
        message: correctedMessage,
        mission_step: resolvedMissionStep,
        latitude: latitude || null,
        longitude: longitude || null,
        photo_url: validatedPhotoUrl,
        read_by_admin: 0
      });
      if (insertError) {
        console.error("[mission-update] Erro Supabase ao inserir:", insertError.message);
        return res.status(500).json({ message: "Erro ao salvar atualiza\xE7\xE3o" });
      }
      console.log(`[mission-update] Atualiza\xE7\xE3o salva: agente=${emp?.name || user.name} OS=${so.osNumber} msg="${correctedMessage.substring(0, 50)}"`);
      try {
        const resetRes = await supabaseAdmin.from("agent_central_reminders").delete().eq("service_order_id", serviceOrderId);
        if (resetRes.error) {
          console.warn("[agent-central] reset falhou:", resetRes.error.message);
        }
      } catch (e) {
        console.warn("[agent-central] reset exception:", e.message);
      }
      res.json({ success: true });
      Promise.resolve().then(() => (init_agent_central_mention(), agent_central_mention_exports)).then(
        ({ fulfillGroupRequests: fulfillGroupRequests2 }) => fulfillGroupRequests2({
          serviceOrderId,
          osNumber: so.osNumber || null,
          employeeName: emp?.name || user.name || null,
          message: correctedMessage,
          hadPhoto: !!validatedPhotoUrl,
          missionStep: resolvedMissionStep
        })
      ).catch((e) => console.warn("[agent-central] fulfill falhou:", e?.message));
    } catch (err) {
      console.error("[mission-update] Erro ao salvar:", err.message);
      res.status(500).json({ message: "Erro ao salvar atualiza\xE7\xE3o" });
    }
  });
