      const [y, m] = mes.split("-").map(Number);
      const { payrollPeriodRange: payrollPeriodRange2 } = await Promise.resolve().then(() => (init_holidays(), holidays_exports));
      const periodo = payrollPeriodRange2(y, m);
      const inicioMes = `${periodo.from}T00:00:00-03:00`;
