// server/lib/financial-cancel-guard.ts
function canCancelAguardando(tx) {
  if (!tx) {
    return { ok: false, code: 404, message: "Lan\xE7amento n\xE3o encontrado" };
  }
  if (tx.origin_type && tx.origin_type !== "manual") {
    return {
      ok: false,
      code: 403,
      message: "Lan\xE7amentos autom\xE1ticos n\xE3o podem ser cancelados manualmente."
    };
  }
  if (tx.status !== "AGUARDANDO_APROVACAO") {
    return {
      ok: false,
      code: 403,
      message: "S\xF3 d\xE1 pra cancelar enquanto o lan\xE7amento aguarda aprova\xE7\xE3o da diretoria. Depois de aprovado ou recusado, fale com a diretoria."
    };
  }
  return { ok: true };
}

// server/lib/recusada-guard.ts
async function osIsRecusada(sb, serviceOrderId) {
  if (serviceOrderId == null || serviceOrderId === "") return false;
  try {
    const { data } = await sb.from("service_orders").select("status").eq("id", serviceOrderId).maybeSingle();
    return data?.status === "recusada";
  } catch {
    return false;
  }
}
function buildRecusadaZeroPayload(motivo, observacaoAtual) {
  let observacoes = "OS RECUSADA";
  if (observacaoAtual && observacaoAtual.startsWith("OS RECUSADA")) {
    observacoes = observacaoAtual;
  } else if (motivo && motivo.trim()) {
    observacoes = `OS RECUSADA \u2014 ${motivo.trim()}`;
  }
  return {
    status: "CANCELADO",
    fat_total: 0,
    fat_acionamento: 0,
    fat_hora_extra: 0,
    fat_km: 0,
    fat_km_carregado: 0,
    fat_km_vazio: 0,
    fat_estadia: 0,
    fat_pernoite: 0,
    fat_diaria: 0,
    fat_adicional_noturno: 0,
    resultado_bruto: 0,
    resultado_liquido: 0,
    margem_percentual: 0,
    observacoes
  };
}

