function calcLeadScore(setor, endereco, temperatura, valor_estimado) {
  let score = SCORING_SETOR[setor || ""] || 3;
  const addr = (endereco || "").toLowerCase();
  for (const zona of ZONAS_RISCO) {
    if (addr.includes(zona.toLowerCase())) {
      score += 2;
      break;
    }
  }
  if (temperatura === "quente") score += 3;
  else if (temperatura === "morno") score += 1;
  if ((valor_estimado || 0) >= 5e4) score += 2;
  else if ((valor_estimado || 0) >= 2e4) score += 1;
  return Math.min(score, 15);
}
