async function getVehiclePhotosForEmail(baseUrl) {
  try {
    const { data: vehicles4 } = await supabaseAdmin.from("vehicles").select("id, photo_front, photo_left, photo_rear, photo_right").not("photo_front", "is", null).limit(6);
    if (!vehicles4 || vehicles4.length === 0) return "";
    const photosHtml = [];
    let count = 0;
    for (const v of vehicles4) {
      if (count >= 4) break;
      const photoFields = ["photo_front", "photo_left"];
      for (const field of photoFields) {
        if (count >= 4) break;
        const photo = v[field];
        if (!photo) continue;
        const photoUrl = `${baseUrl}/api/leads/vehicle-photo/${v.id}/${field}`;
        photosHtml.push(
          `<td style="padding:4px;width:50%;"><img src="${photoUrl}" width="260" style="width:100%;max-width:260px;height:auto;border-radius:8px;display:block;" alt="Viatura Torres" /></td>`
        );
        count++;
      }
    }
    if (photosHtml.length === 0) return "";
    const rows = [];
    for (let i = 0; i < photosHtml.length; i += 2) {
      rows.push(`<tr>${photosHtml[i]}${photosHtml[i + 1] || "<td></td>"}</tr>`);
    }
    return `
    <div style="margin:20px 0;">
      <p style="color:#1a1a2e;font-weight:bold;font-size:14px;margin:0 0 12px;text-align:center;">Nossa Frota</p>
      <table cellpadding="0" cellspacing="0" border="0" width="100%" style="max-width:540px;margin:0 auto;">
        ${rows.join("")}
      </table>
    </div>`;
  } catch (err) {
    console.error("[leads] Erro ao buscar fotos ve\xEDculos:", err.message);
    return "";
  }
}
