      const cols = splitCsvLine(raw);
      const codigo = (cols[iCod] || "").trim();
      const data = ddmmyyyyToIso((cols[iData] || "").trim());
      const placa = (cols[iPlaca] || "").replace(/[\s\t"]/g, "").toUpperCase();
      if (!codigo || !data || !placa) continue;
