async function ensureCategoryHierarchy() {
  try {
    const migrations = [
      "ALTER TABLE financial_categories ADD COLUMN IF NOT EXISTS parent_name TEXT",
      // Map existing categories to parent groups (case-insensitive name match)
      `UPDATE financial_categories SET parent_name = 'Escrit\xF3rio'
         WHERE parent_name IS NULL AND LOWER(name) IN (
           'material de escrit\xF3rio','servi\xE7os de ti','telecomunica\xE7\xF5es',
           'energia e \xE1gua','energia e agua','marketing','advocacia/cont\xE1bil',
           'aluguel e condom\xEDnio','aluguel e condominio'
         )`,
      `UPDATE financial_categories SET parent_name = 'Carros'
         WHERE parent_name IS NULL AND LOWER(name) IN (
           'combust\xEDvel','combustivel','manuten\xE7\xE3o veicular','manutencao veicular','pe\xE7as e pneus','pecas e pneus'
         )`,
      `UPDATE financial_categories SET parent_name = 'Funcion\xE1rios'
         WHERE parent_name IS NULL AND LOWER(name) IN (
           'equipamentos','uniformes e epi','uniformes','alimenta\xE7\xE3o','alimentacao','viagem/hospedagem'
         )`,
      `UPDATE financial_categories SET parent_name = 'Armamento'
         WHERE parent_name IS NULL AND LOWER(name) IN (
           'armamento e muni\xE7\xE3o','armamento e municao','armamento'
         )`
    ];
    for (const q of migrations) {
      await supabaseAdmin.rpc("exec_sql", { query: q });
    }
    const seedCategories = [
      { name: "Aluguel Casa", parent_name: "Escrit\xF3rio", type: "EXPENSE", group: "DESPESAS_FIXAS" },
      { name: "Escrit\xF3rio", parent_name: "Escrit\xF3rio", type: "EXPENSE", group: "DESPESAS_FIXAS" },
      { name: "TI", parent_name: "Escrit\xF3rio", type: "EXPENSE", group: "DESPESAS_FIXAS" },
      { name: "Telefones", parent_name: "Escrit\xF3rio", type: "EXPENSE", group: "DESPESAS_FIXAS" },
      { name: "Energia / \xC1gua", parent_name: "Escrit\xF3rio", type: "EXPENSE", group: "DESPESAS_FIXAS" },
      { name: "Marketing", parent_name: "Escrit\xF3rio", type: "EXPENSE", group: "DESPESAS_FIXAS" },
      { name: "Jur\xEDdico", parent_name: "Escrit\xF3rio", type: "EXPENSE", group: "DESPESAS_FIXAS" },
      { name: "Material de Escrit\xF3rio", parent_name: "Escrit\xF3rio", type: "EXPENSE", group: "DESPESAS_FIXAS" },
      { name: "Aluguel Carros", parent_name: "Carros", type: "EXPENSE", group: "CUSTOS_VARIAVEIS" },
      { name: "Combust\xEDvel", parent_name: "Carros", type: "EXPENSE", group: "CUSTOS_VARIAVEIS" },
      { name: "Manuten\xE7\xE3o", parent_name: "Carros", type: "EXPENSE", group: "CUSTOS_VARIAVEIS" },
      { name: "Equipamentos", parent_name: "Funcion\xE1rios", type: "EXPENSE", group: "DESPESAS_FIXAS" },
      { name: "Uniformes", parent_name: "Funcion\xE1rios", type: "EXPENSE", group: "DESPESAS_FIXAS" },
      { name: "Seguros", parent_name: "Funcion\xE1rios", type: "EXPENSE", group: "DESPESAS_FIXAS" },
      { name: "Armas", parent_name: "Armamento", type: "EXPENSE", group: "CUSTOS_VARIAVEIS" },
      { name: "Muni\xE7\xF5es", parent_name: "Armamento", type: "EXPENSE", group: "CUSTOS_VARIAVEIS" }
    ];
    const { data: existing } = await supabaseAdmin.from("financial_categories").select("name");
    const existingNames = new Set((existing || []).map((c) => c.name.toLowerCase()));
    for (const cat of seedCategories) {
      if (!existingNames.has(cat.name.toLowerCase())) {
        await supabaseAdmin.from("financial_categories").insert({
          ...cat,
          recurrence_type: "VARIAVEL",
          tag: "OPERACIONAL",
          scope: "EMPRESA",
          is_deduction: false
        });
      } else {
        await supabaseAdmin.from("financial_categories").update({ parent_name: cat.parent_name }).ilike("name", cat.name).is("parent_name", null);
      }
    }
    console.log("[categories] Hierarquia de categorias garantida");
  } catch (err) {
    console.warn("[categories] ensureCategoryHierarchy:", err?.message);
  }
}
async function ensureComprovantesBucket() {
  try {
    const { data: buckets } = await supabaseAdmin.storage.listBuckets();
    const exists = (buckets || []).some((b) => b.name === "comprovantes-pagamento");
    if (!exists) {
      const { error } = await supabaseAdmin.storage.createBucket("comprovantes-pagamento", {
        public: false,
        fileSizeLimit: 5 * 1024 * 1024
      });
      if (error && !/already exists/i.test(error.message || "")) {
        console.warn("[storage] createBucket comprovantes-pagamento:", error.message);
      } else {
        console.log("[storage] Bucket 'comprovantes-pagamento' criado (private)");
      }
    }
  } catch (e) {
    console.warn("[storage] ensureComprovantesBucket skipped:", e?.message);
  }
}
